+        sessions: Array.from(this.sessions.values())
+          .map(session => ({
+            ...session,
+            profile: this.sessionProfiles.get(session.id)!,
+          }))
+          .filter(s => s.profile),
+        metrics: {
+          completedTasks: 0,
+          failedTasks: 0,
+          totalTaskDuration: 0,
+        },
+        savedAt: new Date(),
+      };
+
+      await mkdir(dirname(this.persistencePath), { recursive: true });
