+
+/**
+ * Helper to create a tool definition
+ */
+export function defineTool<TInput = Record<string, unknown>, TOutput = unknown>(
+  name: string,
+  description: string,
+  inputSchema: JSONSchema,
+  handler: ToolHandler<TInput, TOutput>,
+  options?: {
+    category?: string;
+    tags?: string[];
+    version?: string;
+    deprecated?: boolean;
+    cacheable?: boolean;
+    cacheTTL?: number;
+    timeout?: number;
+  }
+): MCPTool<TInput, TOutput> {
+  return {
+    name,
+    description,
+    inputSchema,
+    handler,
+    ...options,
+  };
+}

