+  /**
+   * Fast learning using Micro-LoRA updates
+   * Target: <10ms per batch
+   */
+  async learn(
+    trajectories: Trajectory[],
+    config: SONAModeConfig,
+    ewcState: EWCState
+  ): Promise<number> {
+    const startTime = performance.now();
+
+    if (trajectories.length === 0) return 0;
