+    return Math.max(0, improvementDelta);
+  }
+
+  /**
+   * Apply LoRA with minimal overhead
+   * Target: <0.05ms
+   */
+  async applyLoRA(
+    input: Float32Array,
+    weights?: LoRAWeights
+  ): Promise<Float32Array> {
+    if (!weights) {
+      // No adaptation, return input as-is
+      return input;
+    }
