+      timeoutMs: config.timeoutMs ?? SWARM_CONSTANTS.DEFAULT_CONSENSUS_TIMEOUT_MS,
+      maxRounds: config.maxRounds ?? 10,
+      requireQuorum: config.requireQuorum ?? true,
